import React, { useState } from 'react';
import Header from '../components/Header';
import MovieCard from '../components/MovieCard';
import MoviePlayer from '../components/MoviePlayer';
import { useAuth } from '../contexts/AuthContext';
import { MOVIES } from '../services/api';
import './ForYou.css';

const ForYou = () => {
  const { user } = useAuth();
  const [selectedMovie, setSelectedMovie] = useState(null);

  const handleMovieClick = (movie) => {
    setSelectedMovie(movie);
  };

  const handleClosePlayer = () => {
    setSelectedMovie(null);
  };

  return (
    <>
      <Header />
      <main className="main-content">
        <div className="recommendation-header">
          <h2 className="catalog-title">🎯 ФИЛЬМЫ ДЛЯ ВАС</h2>
          <span className="recommendation-badge">персональные рекомендации</span>
        </div>

        <div className="personalized-note">
          {user ? (
            <><span>{user.username}</span>, мы подобрали фильмы специально для вас 🔥</>
          ) : (
            <><span>Рекомендации для вас</span> — зарегистрируйтесь, чтобы получать персональные подборки</>
          )}
        </div>

        <div className="movies-grid">
          {Object.values(MOVIES).map(movie => (
            <MovieCard
              key={movie.id}
              movie={movie}
              onClick={() => handleMovieClick(movie)}
            />
          ))}
        </div>
      </main>
      {selectedMovie && (
        <MoviePlayer movie={selectedMovie} onClose={handleClosePlayer} />
      )}
    </>
  );
};

export default ForYou;
